import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.*;
import java.util.HashMap;
import java.util.Map;

public class ConfigParser {
    public static Map<String, String> parseConfig(InputStream inputStream) throws Exception {
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        DocumentBuilder builder = factory.newDocumentBuilder();
        Document doc = builder.parse(inputStream);

        Map<String, String> config = new HashMap<>();
        NodeList settingNodes = doc.getElementsByTagName("setting");
        for (int i = 0; i < settingNodes.getLength(); i++) {
            Element settingElement = (Element) settingNodes.item(i);
            String key = settingElement.getAttribute("key");
            String value = settingElement.getTextContent();
            config.put(key, value);
        }

        return config;
    }
}